import React from 'react'
import { useState } from 'react'
import { Route, Routes, Navigate} from "react-router-dom"

function NuovaPartita() {
  const [beenClicked, setBeenClicked] = useState(false);

  function newGame(){
    setBeenClicked(true);
  }

  return (
    <>
      {beenClicked && <Navigate to={`/matches/${ parseInt(Math.random() * 1000000000)}`} replace/>}
      <div onClick={newGame} className="center" id="nuovaPartita">Nuova Partita</div>
    </>
  )
}

export default NuovaPartita
